#!/bin/bash

# Set environment variables
export AWS_ACCESS_KEY_ID=<your_access_key_id>
export AWS_SECRET_ACCESS_KEY=<your_secret_access_key>
export AWS_REGION=<your_region>

# Specify the deployment parameters
APP_NAME=<your_app_name>
VERSION=<your_version>

# Deploy the application
aws deploy create-deployment \
    --application-name $APP_NAME \
    --deployment-config-name <your_deployment_config_name> \
    --version-label $VERSION

# Monitor the deployment progress
aws deploy wait deployment-successful --deployment-id $(aws deploy list-deployments --application-name $APP_NAME --version-label $VERSION --max-items 1 --query Deployments[0].DeploymentId)

# Print success message
echo "Deployment successful!"